-- Regenerate all system option configuration records to ensure
-- most up-to-date versions are always present after an upgrade
-- Product:      Pure Insurance
-- Last updated: 7/21/2021 7:36:16 PM
IF EXISTS (SELECT * FROM Hidden_Options WHERE option_number = 1 and value = 'U')
BEGIN
	-- Delete all current options and groups
	DELETE FROM system_option_configuration
	DELETE FROM system_option_configuration_group

	-- Add Security root group

	-- Add Password Management group

	-- Add General group

	-- Add Document Production group

	-- Add Accounts root group

	-- Add General group

	-- Add Age Analysis Bands group

	-- Add Agent Analysis Bands group

	-- Add Underwriting root group

	-- Add General group

	-- Add Claims group

	-- Add Renewal group

	-- Add Import/Export group

	-- Add SAM root group

	-- Add General group

	-- Add Work Manager Tasks group

	-- Add Compiled Rules group

	-- Ensure all configured options at least have a default record
	SELECT DISTINCT s.source_id, soc.option_number, null, Max(soc.control_caption)
		FROM system_option_configuration soc, source s
		WHERE soc.option_number Is Not Null
		AND NOT EXISTS (SELECT * FROM system_options so WHERE so.branch_id = s.source_id AND so.option_number = soc.option_number)
		GROUP BY s.source_id, soc.option_number
		ORDER BY source_id, option_number
END
GO

